    private Allergy selectedAllergy;

    public void initData(User admin) {
        setupSeverityCombo();
        setupTable();
        loadAllergies();
    }

    private void setupSeverityCombo() {
        if (comboSeverity != null) {
            comboSeverity.setItems(FXCollections.observableArrayList("Leve", "Moderada", "Severa"));
